public int makeChocolate(int small, int big, int goal) {
    if (goal > 5*big + small) {
        return -1;
    }

    int neededSmall = goal - 5 * Math.min(big, goal/5);

    if (neededSmall <= small) {
        return neededSmall;
    } else {
        return -1;
