public int[] fix45(int[] nums) {

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 4) {
            for (int j = i + 1; j < nums.length; j++) {
                if (nums[j] == 5) {
                    int temp = nums[j];
                    nums[j] = nums[i + 1];
                    nums[i + 1] = temp;
                    break;
                }
            }
        }
    }
    return nums;
}

java
public int[] fix45(int[] nums) {
    int i = 0, j = 0;
    while (j < nums.length) {
        if (nums[j] == 5) {
            j++;
        } else if (nums[j] == 4) {
            while (nums[i] != 5) {
                i++;
            }
            int temp = nums[i];
            nums[i] = nums[j];
            nums[j] = temp;
            i++;
            j++;
        } else {
            j++;
        }
    }
    return nums;
}

