public boolean xyBalance(String str) {
    int unBalancedX = 0;

    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            unBalancedX++;
        } else if (str.charAt(i) == 'y') {
            unBalancedX = Math.max(0, unBalancedX - 1);
        }
    }

    return unBalancedX == 0;
}

